namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Services;

public class MockSettingsService : ISettingsService
{
    private UserProfile _profile = new(
        "Jane Doe",
        "jane.doe@example.com",
        "https://via.placeholder.com/120",
        "Software developer passionate about building great user experiences."
    );

    private NotificationPrefs _notificationPrefs = new(
        EmailNotifications: true,
        PushNotifications: true,
        WeeklyDigest: false,
        MutedChannels: ["announcements", "random", "social", "dev-ops", "design"]
    );

    private SecuritySettings _security = new(
        TwoFactorEnabled: false,
        LastPasswordChange: DateTime.UtcNow.AddDays(-45),
        Sessions:
        [
            new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
            new("sess-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
            new("sess-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-3)),
        ]
    );

    private AppearanceSettings _appearance = new("Light", "Medium", "English", false);

    public Task<UserProfile> GetProfileAsync() =>
        Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() =>
        Task.FromResult(_notificationPrefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notificationPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() =>
        Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        _security = _security with
        {
            Sessions = _security.Sessions.Where(s => s.Id != sessionId).ToList()
        };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() =>
        Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<nav class="settings-sidebar" aria-label="Settings navigation">
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li>
                <button class="settings-nav-btn @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="settings-nav-icon">@GetIcon(section)</span>
                    <span>@section</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<section class="settings-section" aria-labelledby="profile-heading">
    <h2 id="profile-heading">Profile</h2>
    <p class="section-description">Manage your personal information and public profile.</p>

    <div class="profile-layout">
        <div class="avatar-area">
            <img src="@AvatarUrl" alt="Avatar preview" class="avatar-preview" />
            <span class="avatar-url-label">@AvatarUrl</span>
        </div>

        <div class="profile-fields">
            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" class="form-control" @bind="DisplayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="Email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success" role="status">@StatusMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public string DisplayName { get; set; } = "";
    [Parameter, EditorRequired] public string Email { get; set; } = "";
    [Parameter, EditorRequired] public string Bio { get; set; } = "";
    [Parameter, EditorRequired] public string AvatarUrl { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<(string DisplayName, string Email, string Bio)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnDiscard { get; set; }

    private bool IsSaving;
    private string? StatusMessage;

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        await OnSave.InvokeAsync((DisplayName, Email, Bio));
        StatusMessage = "Profile saved successfully!";
        IsSaving = false;
    }

    private async Task Discard()
    {
        StatusMessage = null;
        await OnDiscard.InvokeAsync();
    }
}

@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<section class="settings-section" aria-labelledby="notifications-heading">
    <h2 id="notifications-heading">Notifications</h2>
    <p class="section-description">Choose how and when you want to be notified.</p>

    <div class="toggle-group">
        <label class="toggle-row">
            <span>Email Notifications</span>
            <input type="checkbox" class="toggle-switch" @bind="EmailNotifications" />
        </label>
        <label class="toggle-row">
            <span>Push Notifications</span>
            <input type="checkbox" class="toggle-switch" @bind="PushNotifications" />
        </label>
        <label class="toggle-row">
            <span>Weekly Digest</span>
            <input type="checkbox" class="toggle-switch" @bind="WeeklyDigest" />
        </label>
    </div>

    <h3>Muted Channels</h3>
    <p class="section-description">Select channels to mute.</p>

    <div class="channel-list">
        @foreach (var channel in AllChannels)
        {
            <label class="channel-item">
                <input type="checkbox"
                       checked="@MutedChannels.Contains(channel)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <span>#@channel</span>
            </label>
        }
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success" role="status">@StatusMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving…" : "Save Preferences")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public bool EmailNotifications { get; set; }
    [Parameter, EditorRequired] public bool PushNotifications { get; set; }
    [Parameter, EditorRequired] public bool WeeklyDigest { get; set; }
    [Parameter, EditorRequired] public List<string> MutedChannels { get; set; } = [];
    [Parameter, EditorRequired] public List<string> AllChannels { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<(bool Email, bool Push, bool Digest, List<string> Muted)> OnSave { get; set; }

    private bool IsSaving;
    private string? StatusMessage;

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!isMuted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        await OnSave.InvokeAsync((EmailNotifications, PushNotifications, WeeklyDigest, MutedChannels));
        StatusMessage = "Notification preferences saved!";
        IsSaving = false;
    }
}

@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<div class="expandable-panel">
    <button class="panel-toggle" @onclick="() => IsExpanded = !IsExpanded"
            aria-expanded="@IsExpanded">
        <span>🔑 Change Password</span>
        <span class="caret">@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger" role="alert">@ErrorMessage</div>
            }
            @if (!string.IsNullOrEmpty(SuccessMessage))
            {
                <div class="alert alert-success" role="status">@SuccessMessage</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@IsUpdating">
                @(IsUpdating ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private bool IsExpanded;
    private bool IsUpdating;
    private string? ErrorMessage;
    private string? SuccessMessage;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        IsUpdating = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        SuccessMessage = "Password updated successfully!";
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
        IsUpdating = false;
    }
}

@using sv_1e8f1cf9315e4f72b326846ba6165b6a.Services
@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<div class="sessions-section">
    <h3>Active Sessions</h3>

    <table class="table sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-sm btn-outline-danger"
