    [Parameter, EditorRequired] public bool EmailNotifications { get; set; }
    [Parameter, EditorRequired] public bool PushNotifications { get; set; }
    [Parameter, EditorRequired] public bool WeeklyDigest { get; set; }
    [Parameter, EditorRequired] public List<string> MutedChannels { get; set; } = [];
    [Parameter, EditorRequired] public List<string> AllChannels { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<(bool Email, bool Push, bool Digest, List<string> Muted)> OnSave { get; set; }

    private bool IsSaving;
    private string? StatusMessage;

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!isMuted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        await OnSave.InvokeAsync((EmailNotifications, PushNotifications, WeeklyDigest, MutedChannels));
        StatusMessage = "Notification preferences saved!";
        IsSaving = false;
    }
}

