    <p class="section-description">Select channels to mute.</p>

    <div class="channel-list">
        @foreach (var channel in AllChannels)
        {
            <label class="channel-item">
                <input type="checkbox"
                       checked="@MutedChannels.Contains(channel)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <span>#@channel</span>
            </label>
        }
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success" role="status">@StatusMessage</div>
    }

