<div class="expandable-panel">
    <button class="panel-toggle" @onclick="() => IsExpanded = !IsExpanded"
            aria-expanded="@IsExpanded">
        <span>🔑 Change Password</span>
        <span class="caret">@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger" role="alert">@ErrorMessage</div>
            }
            @if (!string.IsNullOrEmpty(SuccessMessage))
            {
                <div class="alert alert-success" role="status">@SuccessMessage</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@IsUpdating">
                @(IsUpdating ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private bool IsExpanded;
    private bool IsUpdating;
    private string? ErrorMessage;
    private string? SuccessMessage;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        IsUpdating = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        SuccessMessage = "Password updated successfully!";
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
        IsUpdating = false;
    }
}
"}

{"path": "/tmp/sv-1e8f1cf9315e4f72b326846ba6165b6a/Components/Pages/Settings/ActiveSessionsTable.razor", "file_text": "@using sv_1e8f1cf9315e4f72b326846ba6165b6a.Services
@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<div class="sessions-section">
    <h3>Active Sessions</h3>

    <table class="table sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-sm btn-outline-danger"
                                    @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (SessionToRevoke is not null)
    {
        <div class="confirm-dialog-backdrop" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation>
                <h4>Revoke Session</h4>
                <p>
                    Are you sure you want to revoke the session on
                    <strong>@SessionToRevoke.Device</strong> in <strong>@SessionToRevoke.Location</strong>?
                </p>
                <div class="confirm-dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                    <button class="btn btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    // The first session is treated as the current session
    private string CurrentSessionId => Sessions.Count > 0 ? Sessions[0].Id : "";

    private ActiveSession? SessionToRevoke;

    private void PromptRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (SessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(SessionToRevoke.Id);
            SessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
"}

