@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<nav class="settings-sidebar" aria-label="Settings navigation">
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li>
                <button class="settings-nav-btn @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="settings-nav-icon">@GetIcon(section)</span>
                    <span>@section</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<section class="settings-section" aria-labelledby="profile-heading">
    <h2 id="profile-heading">Profile</h2>
    <p class="section-description">Manage your personal information and public profile.</p>

    <div class="profile-layout">
        <div class="avatar-area">
            <img src="@AvatarUrl" alt="Avatar preview" class="avatar-preview" />
            <span class="avatar-url-label">@AvatarUrl</span>
        </div>

        <div class="profile-fields">
            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" class="form-control" @bind="DisplayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="Email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success" role="status">@StatusMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public string DisplayName { get; set; } = "";
    [Parameter, EditorRequired] public string Email { get; set; } = "";
    [Parameter, EditorRequired] public string Bio { get; set; } = "";
    [Parameter, EditorRequired] public string AvatarUrl { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<(string DisplayName, string Email, string Bio)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnDiscard { get; set; }

    private bool IsSaving;
    private string? StatusMessage;

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        await OnSave.InvokeAsync((DisplayName, Email, Bio));
        StatusMessage = "Profile saved successfully!";
        IsSaving = false;
    }

    private async Task Discard()
    {
        StatusMessage = null;
        await OnDiscard.InvokeAsync();
    }
}

