<section class="settings-section" aria-labelledby="security-heading">
    <h2 id="security-heading">Security</h2>
    <p class="section-description">Protect your account with passwords and session management.</p>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="two-factor-row">
        <div class="two-factor-info">
            <span class="two-factor-label">Two-Factor Authentication</span>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        <label class="toggle-row">
            <input type="checkbox" class="toggle-switch" @bind="TwoFactorEnabled" />
        </label>
    </div>

    @if (LastPasswordChange.HasValue)
    {
        <p class="text-muted small">
            Last password change: @LastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <ActiveSessionsTable Sessions="Sessions" OnRevoke="OnRevoke" />
</section>

@code {
    [Parameter, EditorRequired] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }
}

@namespace sv_1e8f1cf9315e4f72b326846ba6165b6a.Components.Pages.Settings

<section class="settings-section" aria-labelledby="appearance-heading">
    <h2 id="appearance-heading">Appearance</h2>
    <p class="section-description">Customize the look and feel of your application.</p>

    <div class="appearance-controls">
        <fieldset class="form-group">
            <legend>Theme</legend>
            <div class="radio-group">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <label class="radio-option">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </fieldset>

        <fieldset class="form-group">
            <legend>Font Size</legend>
            <div class="radio-group">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <label class="radio-option">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </fieldset>

        <div class="form-group">
            <label for="language">Language</label>
            <select id="language" class="form-control" @bind="Language">
                @foreach (var lang in Languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <label class="toggle-row">
            <span>Compact Mode</span>
            <input type="checkbox" class="toggle-switch" @bind="CompactMode" />
        </label>
    </div>

    <div class="preview-area @PreviewThemeClass" style="font-size: @PreviewFontSize;">
        <h4>Live Preview</h4>
        <p>This is how your content will look with the selected settings.</p>
        <div class="preview-card">
            <strong>Sample Card</strong>
            <p>Theme: @Theme · Font: @FontSize · Language: @Language</p>
            @if (CompactMode)
            {
                <span class="badge bg-info">Compact</span>
            }
        </div>
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success" role="status">@StatusMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving…" : "Save")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public string Theme { get; set; } = "Light";
    [Parameter, EditorRequired] public string FontSize { get; set; } = "Medium";
    [Parameter, EditorRequired] public string Language { get; set; } = "English";
    [Parameter, EditorRequired] public bool CompactMode { get; set; }
    [Parameter, EditorRequired]
    public EventCallback<(string Theme, string FontSize, string Language, bool CompactMode)> OnSave { get; set; }

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private bool IsSaving;
    private string? StatusMessage;

    private string PreviewThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string PreviewFontSize => FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        await OnSave.InvokeAsync((Theme, FontSize, Language, CompactMode));
        StatusMessage = "Appearance settings saved!";
        IsSaving = false;
    }
}

