                case "Notifications":
                    <NotificationsSection EmailNotifications="@notifPrefs!.EmailNotifications"
                                          PushNotifications="@notifPrefs.PushNotifications"
                                          WeeklyDigest="@notifPrefs.WeeklyDigest"
                                          MutedChannels="@mutedChannels"
                                          AllChannels="@allChannels"
                                          OnSave="SaveNotificationsAsync" />
                    break;

                case "Security":
                    <SecuritySection TwoFactorEnabled="@security!.TwoFactorEnabled"
                                     LastPasswordChange="@security.LastPasswordChange"
                                     Sessions="@security.Sessions"
                                     OnChangePassword="ChangePasswordAsync"
