toolArgs.file_text:
/* ───── Settings Dashboard Layout ───── */

.settings-dashboard {
    display: flex;
    min-height: 80vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

/* ───── Sidebar ───── */

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

.settings-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.settings-nav-btn {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.75rem 1.25rem;
    border: none;
    background: transparent;
    cursor: pointer;
    font-size: 0.95rem;
    color: #495057;
    text-align: left;
    transition: background 0.15s, color 0.15s;
}

.settings-nav-btn:hover {
    background: #e9ecef;
}

.settings-nav-btn.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.15rem;
}

/* ───── Content Area ───── */

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h2 {
    margin: 0 0 0.25rem;
    font-size: 1.5rem;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.loading-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 200px;
    color: #6c757d;
    font-size: 1.1rem;
}

/* ───── Form Helpers ───── */

.form-group {
    margin-bottom: 1rem;
}

.form-group label,
.form-group legend {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    font-size: 0.9rem;
}

.form-group legend {
    border: none;
    padding: 0;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

/* ───── Profile ───── */

.profile-layout {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.avatar-area {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-url-label {
    font-size: 0.75rem;
    color: #6c757d;
    max-width: 140px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.profile-fields {
    flex: 1;
}

/* ───── Toggle Rows ───── */

.toggle-group {
    margin-bottom: 1.5rem;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.65rem 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
}

.toggle-switch {
    width: 40px;
    height: 22px;
    accent-color: #0d6efd;
    cursor: pointer;
}

/* ───── Channels ───── */

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    margin-bottom: 1rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.35rem 0;
    cursor: pointer;
}

/* ───── Expandable Panel ───── */

.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-toggle {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.85rem 1rem;
    border: none;
    background: #f8f9fa;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.95rem;
}

.panel-toggle:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ───── Two-Factor ───── */

.two-factor-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1rem 0;
    border-bottom: 1px solid #f0f0f0;
    margin-bottom: 1rem;
}

.two-factor-info {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.two-factor-label {
    font-weight: 600;
}

/* ───── Sessions Table ───── */

.sessions-section {
    margin-top: 1.5rem;
}

.sessions-table {
    width: 100%;
    font-size: 0.9rem;
}

.sessions-table th {
    font-weight: 600;
    border-bottom: 2px solid #dee2e6;
    padding: 0.5rem;
}

.sessions-table td {
    padding: 0.5rem;
    border-bottom: 1px solid #f0f0f0;
    vertical-align: middle;
}

/* ───── Confirmation Dialog ───── */

.confirm-dialog-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.confirm-dialog {
    background: #fff;
    border-radius: 8px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.15);
}

.confirm-dialog h4 {
    margin: 0 0 0.75rem;
}

.confirm-dialog-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
    justify-content: flex-end;
}

/* ───── Appearance ───── */

.radio-group {
    display: flex;
    gap: 1.25rem;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    cursor: pointer;
}

.appearance-controls {
    margin-bottom: 1.5rem;
}

/* ───── Live Preview ───── */

.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 1.25rem;
    margin-bottom: 1rem;
    transition: background 0.2s, color 0.2s;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-card {
    background: rgba(128, 128, 128, 0.1);
    border-radius: 4px;
    padding: 0.75rem;
    margin-top: 0.5rem;
}

/* ───── Alerts ───── */

.alert {
    padding: 0.65rem 1rem;
    border-radius: 4px;
    margin-top: 0.75rem;
    font-size: 0.9rem;
}

.alert-success {
    background: #d1e7dd;
    color: #0f5132;
}

.alert-danger {
    background: #f8d7da;
    color: #842029;
}

/* ───── Badges ───── */

.badge {
    display: inline-block;
    padding: 0.25rem 0.6rem;
    border-radius: 4px;
    font-size: 0.8rem;
    font-weight: 600;
}

.bg-success {
    background: #198754;
    color: #fff;
}

.bg-secondary {
    background: #6c757d;
    color: #fff;
}

.bg-info {
    background: #0dcaf0;
    color: #000;
}

